using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","in","on","at","to","for",
        "of","with","by","from","as","into","about","between","through","after",
        "above","below","up","down","out","off","over","under","then","than",
        "so","no","not","only","very","just","that","this","it","its","i","we",
        "they","he","she","you","my","your","his","her","our","their","what",
        "which","who","whom","when","where","how","all","each","every","both",
        "few","more","most","other","some","such","also","back","even","still"
    ];

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(text);

        var scored = sentences
            .Select((sentence, index) => new
            {
                Sentence = sentence,
                Index = index,
                Score = ScoreSentence(sentence, wordFrequencies, index, sentences.Count)
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(string text)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var word in WordRegex().Matches(text).Select(m => m.Value.ToLowerInvariant()))
        {
            if (word.Length > 1 && !StopWords.Contains(word))
                frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
        }
        return frequencies;
    }

    private static double ScoreSentence(
        string sentence,
        Dictionary<string, int> wordFrequencies,
        int position,
        int totalSentences)
    {
        var words = WordRegex().Matches(sentence).Select(m => m.Value.ToLowerInvariant()).ToList();
        if (words.Count == 0) return 0;

        double freqScore = words
            .Where(w => wordFrequencies.ContainsKey(w))
            .Sum(w => wordFrequencies[w]);
        freqScore /= words.Count;

        // Boost first and last sentences as they often carry key information
        double positionBoost = position == 0 ? 1.5
            : position == totalSentences - 1 ? 1.2
            : 1.0;

        return freqScore * positionBoost;
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordRegex();
}

using System.Text.RegularExpressions;
using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public partial class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizer _summarizer = new();

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = WordCount().Matches(request.DocumentText).Count,
            SummaryWordCount = WordCount().Matches(summary).Count
        });
    }

    [GeneratedRegex(@"\b\S+\b")]
    private static partial Regex WordCount();
}

